    if (!VODAnalyzer.instance) {
      VODAnalyzer.instance = new VODAnalyzer(pool);
    }
    return VODAnalyzer.instance;
  }

  async analyzeVOD(vodId: number): Promise<void> {
    const client = await this.pool.connect();

    try {
      await client.query('BEGIN');

      // Get VOD information including file path
      const vodResult = await client.query(
        `SELECT v.*, c.twitch_id as channel_twitch_id 
         FROM vods v 
         JOIN channels c ON v.channel_id = c.id 
         WHERE v.id = $1`,
        [vodId]
      );

      if (vodResult.rows.length === 0) {
        throw new Error(`VOD ${vodId} not found`);
      }

      const vod = vodResult.rows[0];

      // Record analysis start
      await client.query(
        `INSERT INTO vod_processing_history (
          vod_id, status, started_at
        ) VALUES ($1, 'analyzing', CURRENT_TIMESTAMP)`,
        [vodId]
      );

      // Get video duration using ffprobe
      const duration = await this.getVideoDuration(vod.file_path);

      // Get game changes during the VOD timeframe
      const gameChanges = await client.query(
        `SELECT * FROM game_changes 
         WHERE channel_id = $1 
         AND changed_at BETWEEN $2 AND $3 
         ORDER BY changed_at`,
        [vod.channel_id, vod.created_at, vod.published_at]
      );

      // Create chapters based on game changes
      const chapters = this.createChaptersFromGameChanges(
        gameChanges.rows,
        vod.created_at,
        duration
      );

      // Store chapters
      for (const chapter of chapters) {
        await client.query(
          `INSERT INTO vod_chapters (
            vod_id, game_id, title, start_time, end_time
          ) VALUES ($1, $2, $3, $4, $5)`,
          [
            vodId,
            chapter.game_id,
            chapter.title,
            chapter.start_time,
            chapter.end_time
          ]
        );
      }

      // Update VOD duration
      await client.query(
        'UPDATE vods SET duration_seconds = $1 WHERE id = $2',
        [duration, vodId]
      );

      // Record successful analysis
      await client.query(
        `UPDATE vod_processing_history 
         SET status = 'completed', completed_at = CURRENT_TIMESTAMP 
         WHERE vod_id = $1 AND completed_at IS NULL`,
        [vodId]
      );

      await client.query('COMMIT');
      logger.info(`Successfully analyzed VOD ${vodId}`);
    } catch (error) {
      await client.query('ROLLBACK');
      logger.error(`Error analyzing VOD ${vodId}:`, error);

      // Record failed analysis
      await client.query(
        `INSERT INTO vod_processing_history (
          vod_id, status, error_message, started_at, completed_at
        ) VALUES ($1, 'failed', $2, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)`,
        [vodId, error.message]
      );

      throw error;
    } finally {
      client.release();
    }
  }

  private async getVideoDuration(filePath: string): Promise<number> {
    return new Promise((resolve, reject) => {
      const ffprobe = spawn('ffprobe', [
        '-v',
        'error',
        '-show_entries',
        'format=duration',
        '-of',
        'default=noprint_wrappers=1:nokey=1',
        filePath
      ]);

      let output = '';

      ffprobe.stdout.on('data', (data) => {
        output += data.toString();
      });

      ffprobe.stderr.on('data', (data) => {
        logger.error(`ffprobe error: ${data}`);
      });

      ffprobe.on('close', (code) => {
        if (code === 0) {
          resolve(Math.floor(parseFloat(output.trim())));
        } else {
          reject(new Error(`ffprobe process exited with code ${code}`));
        }
      });
    });
  }

  async extractGameSegment(
    vodId: number,
    chapterId: number,
    outputPath: string
  ): Promise<void> {
    const client = await this.pool.connect();

    try {
      // Get chapter and VOD information
      const result = await client.query(
        `SELECT v.file_path, c.start_time, c.end_time, c.game_id
         FROM vod_chapters c
         JOIN vods v ON c.vod_id = v.id
         WHERE c.id = $1 AND v.id = $2`,
        [chapterId, vodId]
      );

      if (result.rows.length === 0) {
        throw new Error('Chapter not found');
      }

      const { file_path, start_time, end_time, game_id } = result.rows[0];
      const duration = end_time - start_time;

      // Extract segment using ffmpeg
      await this.extractSegment(
        file_path,
        outputPath,
        start_time,
        duration
      );

      // Record extraction in database
      await client.query(
        `INSERT INTO vod_segments (
          vod_id, chapter_id, game_id, file_path,
          start_time, duration, created_at
        ) VALUES ($1, $2, $3, $4, $5, $6, CURRENT_TIMESTAMP)`,
        [vodId, chapterId, game_id, outputPath, start_time, duration]
      );

    } catch (error) {
      logger.error('Error extracting game segment:', error);
      throw error;
    } finally {
      client.release();
    }
  }

  private async extractSegment(
    inputPath: string,
    outputPath: string,
    startTime: number,
    duration: number
  ): Promise<void> {
    return new Promise((resolve, reject) => {
      const ffmpeg = spawn('ffmpeg', [
        '-i', inputPath,
        '-ss', startTime.toString(),
        '-t', duration.toString(),
        '-c', 'copy',
        outputPath
      ]);

      ffmpeg.stderr.on('data', (data) => {
        logger.debug(`ffmpeg: ${data}`);
      });

      ffmpeg.on('close', (code) => {
        if (code === 0) {
          resolve();
        } else {
          reject(new Error(`ffmpeg process exited with code ${code}`));
        }
      });
    });
  }

  private createChaptersFromGameChanges(
    gameChanges: any[],
    vodStart: Date,
    totalDuration: number
  ): Chapter[] {
    const chapters: Chapter[] = [];
    let currentTime = 0;

    // Add initial chapter if there was a game being played at the start
    if (gameChanges.length > 0) {
      const initialGame = gameChanges[0].previous_game_id;
      if (initialGame) {
        chapters.push({
          game_id: initialGame,
          title: `Game Session: ${initialGame}`,
          start_time: 0,
          end_time: this.getTimeDifferenceInSeconds(vodStart, gameChanges[0].changed_at)
        });
        currentTime = chapters[0].end_time;
      }
    }

    // Add chapters for each game change
    for (let i = 0; i < gameChanges.length; i++) {
      const change = gameChanges[i];
      const nextChange = gameChanges[i + 1];

      const endTime = nextChange
        ? this.getTimeDifferenceInSeconds(vodStart, nextChange.changed_at)
        : totalDuration;

      if (change.new_game_id) {
        chapters.push({
          game_id: change.new_game_id,
          title: `Game Session: ${change.new_game_id}`,
          start_time: currentTime,
          end_time: endTime
        });
      }

      currentTime = endTime;
    }

    return chapters;
  }

  private getTimeDifferenceInSeconds(start: Date, end: Date): number {
    return Math.floor((new Date(end).getTime() - new Date(start).getTime()) / 1000);
  }
}

export const vodAnalyzer = (pool: Pool) => VODAnalyzer.getInstance(pool);
export default vodAnalyzer;

import { Pool } from 'pg';
import axios from 'axios';
import fs from 'fs';
import path from 'path';
import { logger } from '../../utils/logger';
import { mediaServer } from '../media/server';
import { handleError, AppError } from '../../utils/error';

interface DownloadTask {
  id: number;
  vod_id: number;
  chapter_id: number | null;
  priority: number;
  status: string;
}

class VODDownloader {
  private pool: Pool;
  private tempDir: string;
  private maxConcurrent: number;
  private activeDownloads: Set<number>;
  private retryAttempts: number;
  private retryDelay: number;
  private static instance: VODDownloader;

  private constructor(pool: Pool, config: {
    tempDir: string;
    maxConcurrent: number;
    retryAttempts: number;
    retryDelay: number;
  }) {
    this.pool = pool;
    this.tempDir = config.tempDir;
    this.maxConcurrent = config.maxConcurrent;
    this.retryAttempts = config.retryAttempts;
    this.retryDelay = config.retryDelay;
    this.activeDownloads = new Set();

    if (!fs.existsSync(this.tempDir)) {
      fs.mkdirSync(this.tempDir, { recursive: true });
    }
  }

  public static getInstance(pool: Pool, config: {
    tempDir: string;
    maxConcurrent: number;
    retryAttempts: number;
    retryDelay: number;
  }): VODDownloader {
    if (!VODDownloader.instance) {
      VODDownloader.instance = new VODDownloader(pool, config);
    }
    return VODDownloader.instance;
  }

  private async handleDownloadError(error: unknown, vodId: number): Promise<void> {
    const appError = handleError(error);
    logger.error(`Error downloading VOD ${vodId}:`, appError);

    const client = await this.pool.connect();
    try {
      await client.query(
        'UPDATE vod_downloads SET error_message = $1, status = $2 WHERE vod_id = $3',
        [appError.message, 'failed', vodId]
      );
    } finally {
      client.release();
    }
  }

  async addToQueue(vodId: number, chapterId: number | null = null, priority: number = 1): Promise<void> {
    const client = await this.pool.connect();

    try {
      await client.query('BEGIN');

      const vodExists = await client.query(
        'SELECT id FROM vods WHERE id = $1',
        [vodId]
      );

      if (vodExists.rows.length === 0) {
        throw new Error(`VOD ${vodId} not found`);
      }

      const queueCheck = await client.query(
        'SELECT id FROM download_queue WHERE vod_id = $1 AND (chapter_id = $2 OR ($2 IS NULL AND chapter_id IS NULL))',
        [vodId, chapterId]
      );

      if (queueCheck.rows.length === 0) {
        await client.query(
          `INSERT INTO download_queue (
            vod_id, chapter_id, priority, status
          ) VALUES ($1, $2, $3, $4)`,
          [vodId, chapterId, priority, 'pending']
        );
      }

      await client.query('COMMIT');
    } catch (error) {
      await client.query('ROLLBACK');
      logger.error('Error adding to download queue:', error);
      throw error;
    } finally {
      client.release();
    }
  }

  private async processDownload(task: DownloadTask): Promise<void> {
    const client = await this.pool.connect();

    try {
      const vodResult = await client.query(
        'SELECT twitch_vod_id, url FROM vods WHERE id = $1',
        [task.vod_id]
      );

      if (vodResult.rows.length === 0) {
        throw new Error(`VOD ${task.vod_id} not found`);
      }

      const vod = vodResult.rows[0];
      const tempFilePath = path.join(this.tempDir, `${vod.twitch_vod_id}.mp4`);

      await client.query(
        'UPDATE download_queue SET status = $1 WHERE id = $2',
        ['downloading', task.id]
      );

      const response = await axios({
        method: 'GET',
        url: vod.url,
        responseType: 'stream',
      });

      const writer = fs.createWriteStream(tempFilePath);
      response.data.pipe(writer);

      await new Promise((resolve, reject) => {
        writer.on('finish', resolve);
        writer.on('error', reject);
      });

      // Move file to media server
      const finalPath = await mediaServer(this.pool).organizeVOD(task.vod_id, tempFilePath);

      await client.query(
        `INSERT INTO vod_downloads (
          vod_id, download_path, download_status,
          started_at, completed_at, file_size
        ) VALUES ($1, $2, $3, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, $4)`,
        [task.vod_id, finalPath, 'completed', fs.statSync(finalPath).size]
      );

      await client.query(
        'DELETE FROM download_queue WHERE id = $1',
        [task.id]
      );

      logger.info(`Successfully downloaded VOD ${task.vod_id}`);
    } catch (error) {
      logger.error(`Error downloading VOD ${task.vod_id}:`, error);

      await client.query(
        'UPDATE download_queue SET status = $1, error_message = $2 WHERE id = $3',
        ['failed', error.message, task.id]
      );

      await client.query(
        `INSERT INTO vod_downloads (
          vod_id, download_status, started_at,
          completed_at, error_message
        ) VALUES ($1, $2, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, $3)`,
        [task.vod_id, 'failed', error.message]
      );
    } finally {
      this.activeDownloads.delete(task.id);
      client.release();
    }
  }

  async startProcessing(intervalSeconds: number = 30): Promise<void> {
    logger.info(`Starting download queue processing with ${intervalSeconds} second interval`);

    setInterval(() => {
      this.processQueue().catch(error => {
        logger.error('Error in download queue interval:', error);
      });
    }, intervalSeconds * 1000);

    await this.processQueue();
  }

  private async processQueue(): Promise<void> {
    try {
      const result = await this.pool.query<DownloadTask>(
        `SELECT * FROM download_queue 
         WHERE status = 'pending' 
         ORDER BY priority DESC, created_at ASC 
         LIMIT $1`,
        [this.maxConcurrent - this.activeDownloads.size]
      );

      for (const task of result.rows) {
        if (this.activeDownloads.size >= this.maxConcurrent) break;

        this.activeDownloads.add(task.id);
        this.processDownload(task).catch(error => {
          logger.error(`Error processing download task ${task.id}:`, error);
        });
      }
    } catch (error) {
      logger.error('Error processing download queue:', error);
    }
  }

  async getQueueStatus(): Promise<{ pending: number; downloading: number; failed: number; }> {
    const result = await this.pool.query(`
      SELECT 
        COUNT(CASE WHEN status = 'pending' THEN 1 END) as pending,
        COUNT(CASE WHEN status = 'downloading' THEN 1 END) as downloading,
        COUNT(CASE WHEN status = 'failed' THEN 1 END) as failed
      FROM download_queue
    `);

    return {
      pending: parseInt(result.rows[0].pending) || 0,
      downloading: parseInt(result.rows[0].downloading) || 0,
      failed: parseInt(result.rows[0].failed) || 0
    };
  }

  async cleanupTempFiles(maxAgeHours: number = 24): Promise<void> {
    try {
      const maxAge = maxAgeHours * 60 * 60 * 1000;
      const files = fs.readdirSync(this.tempDir);
      const now = Date.now();

      for (const file of files) {
        const filePath = path.join(this.tempDir, file);
        const stats = fs.statSync(filePath);
        if (now - stats.mtimeMs > maxAge) {
          fs.unlinkSync(filePath);
          logger.info(`Cleaned up temp file: ${file}`);
        }
      }
    } catch (error) {
      logger.error('Error cleaning up temp files:', error);
      throw error;
    }
  }
}

export const vodDownloader = (pool: Pool, config: {
  tempDir: string;
  maxConcurrent: number;
  retryAttempts: number;
  retryDelay: number;
}) => VODDownloader.getInstance(pool, config);

export default vodDownloader;

